        dist = Math.abs(z - x[i]);
        if (dist < min_dist) {
            nearest = i;
            min_dist = dist;
        }
    }
    // initial approximation to the function value at z
    value = y[nearest];
    for (i = 1; i < n; i++) {
        for (j = 0; j < n - i; j++) {
            tc = x[j] - z;
            td = x[i + j] - z;
            divider = x[j] - x[i + j];
            if (divider == 0.0) {
                // This happens only when two abscissas are identical.
                throw new DuplicateSampleAbscissaException(x[i], i, i + j);
            }
            // update the difference arrays
            w = (c[j + 1] - d[j]) / divider;
            c[j] = tc * w;
            d[j] = td * w;
        }
        // sum up the difference terms to get the final value
        if (nearest < 0.5 * (n - i + 1)) {
            // fork down
            value += c[nearest];
        } else {
            nearest--;
            // fork up
            value += d[nearest];
        }
    }
    return value;
}

