{
    clearResult();
    verifyInterval(min, max);
    // Index 0 is the old approximation for the root.
    // Index 1 is the last calculated approximation  for the root.
    // Index 2 is a bracket for the root with respect to x0.
    // OldDelta is the length of the bracketing interval of the last
    // iteration.
    double x0 = min;
    double x1 = max;
    double y0 = f.value(x0);
    double y1 = f.value(x1);
    // Verify bracketing
    if (y0 * y1 >= 0) {
        throw new IllegalArgumentException("Function values at endpoints do not have different signs." + "  Endpoints: [" + min + "," + max + "]" + "  Values: [" + y0 + "," + y1 + "]");
    }
    double x2 = x0;
    double y2 = y0;
    double oldDelta = x2 - x1;
    int i = 0;
    while (i < maximalIterationCount) {
        if (Math.abs(y2) < Math.abs(y1)) {
            x0 = x1;
            x1 = x2;
            x2 = x0;
            y0 = y1;
            y1 = y2;
            y2 = y0;
        }
        if (Math.abs(y1) <= functionValueAccuracy) {
            setResult(x1, i);
            return result;
        }
        if (Math.abs(oldDelta) < Math.max(relativeAccuracy * Math.abs(x1), absoluteAccuracy)) {
            setResult(x1, i);
            return result;
        }
        double delta;
        if (Math.abs(y1) > Math.abs(y0)) {
            // Function value increased in last iteration. Force bisection.
            delta = 0.5 * oldDelta;
        } else {
            delta = (x0 - x1) / (1 - y0 / y1);
            if (delta / oldDelta > 1) {
                // New approximation falls outside bracket.
                // Fall back to bisection.
                delta = 0.5 * oldDelta;
            }
        }
        x0 = x1;
        y0 = y1;
        x1 = x1 + delta;
        y1 = f.value(x1);
        if ((y1 > 0) == (y2 > 0)) {
            // New bracket is (x0,x1).
            x2 = x0;
            y2 = y0;
        }
        oldDelta = x2 - x1;
        i++;
    }
    throw new MaxIterationsExceededException(maximalIterationCount);
}

