        pivot[row] = row;
    }
    parity = 1;
    singular = false;
    // Loop over columns
    for (int col = 0; col < m; col++) {
        double sum = 0;
        // upper
        for (int row = 0; row < col; row++) {
            final double[] luRow = lu[row];
            sum = luRow[col];
            for (int i = 0; i < row; i++) {
                sum -= luRow[i] * lu[i][col];
            }
            luRow[col] = sum;
        }
        // lower
        // permutation row
        int max = col;
        double largest = Double.NEGATIVE_INFINITY;
        for (int row = col; row < m; row++) {
            final double[] luRow = lu[row];
            sum = luRow[col];
            for (int i = 0; i < col; i++) {
                sum -= luRow[i] * lu[i][col];
            }
            luRow[col] = sum;
            // maintain best permutation choice
            if (Math.abs(sum) > largest) {
                largest = Math.abs(sum);
                max = row;
            }
        }
        // Singularity check
        if (Math.abs(lu[max][col]) < singularityThreshold) {
            singular = true;
            return;
        }
        // Pivot if necessary
        if (max != col) {
            double tmp = 0;
            for (int i = 0; i < m; i++) {
                tmp = lu[max][i];
                lu[max][i] = lu[col][i];
                lu[col][i] = tmp;
            }
            int temp = pivot[max];
            pivot[max] = pivot[col];
            pivot[col] = temp;
            parity = -parity;
        }
        // Divide the lower elements by the "winning" diagonal elt.
        final double luDiag = lu[col][col];
        for (int row = col + 1; row < m; row++) {
            lu[row][col] /= luDiag;
        }
    }
}

